-- B1/B2 Lesen at full official length: 30 items each, official Teil sizes
-- Grounded against Goethe Zertifikat B1 / Goethe-Zertifikat B2 Modellsätze:
--   B1: T1 R/F ×6, T2 MCQ ×6 (2 Texte), T3 Anzeigen A–J ×7 (1 ohne Match),
--       T4 Ja/Nein ×7, T5 MCQ ×4  = 30 Aufgaben, 65 Minuten
--   B2: T1 4 Personen ×9, T2 MCQ ×6, T3 MCQ ×6, T4 Äußerung→Überschrift ×6,
--       T5 Paragraf→Überschrift ×3 = 30 Aufgaben, 65 Minuten

UPDATE test_modules tm
SET
  description = '5 Teile wie in der Prüfung: Richtig/Falsch, Pressetexte, Anzeigen zuordnen, Meinungen, Betriebsordnung. 30 Aufgaben, 65 Minuten.',
  question_count = 30,
  duration_minutes = 65
FROM levels l, skills s
WHERE tm.level_id = l.id AND tm.skill_id = s.id
  AND l.code = 'B1' AND s.code = 'reading';

UPDATE test_modules tm
SET
  description = '5 Teile wie in der Prüfung: Personen zuordnen, zwei Sachtexte, Äußerungen und Überschriften, Vertragstexte. 30 Aufgaben, 65 Minuten.',
  question_count = 30,
  duration_minutes = 65
FROM levels l, skills s
WHERE tm.level_id = l.id AND tm.skill_id = s.id
  AND l.code = 'B2' AND s.code = 'reading';

-- Replace B1 and B2 reading questions
DELETE FROM questions WHERE test_module_id IN (
  SELECT tm.id FROM test_modules tm
  JOIN levels l ON tm.level_id = l.id
  JOIN skills s ON tm.skill_id = s.id
  WHERE l.code IN ('B1','B2') AND s.code = 'reading'
);

INSERT INTO questions (test_module_id, question_text, question_type, options, correct_answer, explanation, "order", exam_part, task_type, points)
SELECT tm.id, E'Blogeintrag, Meine ersten Monate in der Klinik:\n\n„Seit drei Monaten arbeite ich als Pflegerin in Frankfurt. Am Anfang war die größte Hürde nicht die Arbeit selbst, sondern die Sprache: Die Übergaben am Morgen waren so schnell, dass ich nur die Hälfte verstanden habe. Meine Mentorin Sandra hat mir dann geraten, wichtige Fachbegriffe auf Karteikarten zu schreiben, das hat wirklich geholfen. Inzwischen übernehme ich eigene Patienten und fühle mich im Team akzeptiert. Nur an die Frühschichten um 6 Uhr habe ich mich noch immer nicht gewöhnt. Nächsten Monat beginne ich einen B2-Kurs, den meine Klinik bezahlt. Wenn alles klappt, möchte ich mich in zwei Jahren zur Stationsleitung weiterbilden.“\n\nAussage: Die Autorin arbeitet seit drei Monaten in Frankfurt.', 'multiple_choice', '["Richtig", "Falsch"]'::jsonb, 'Richtig', 'Erster Satz: „Seit drei Monaten arbeite ich als Pflegerin in Frankfurt.“', 1, 1, 'true_false', 1
FROM test_modules tm JOIN levels l ON tm.level_id = l.id JOIN skills s ON tm.skill_id = s.id
WHERE l.code = 'B1' AND s.code = 'reading';

