SELECT tm.id, E'Pressetext 1, Fachkräfte aus dem Ausland:\n\n„Deutsche Krankenhäuser werben zunehmend im Ausland um Personal. Besonders gefragt sind Pflegekräfte aus Ländern mit anerkannten Ausbildungsstandards. Der Verband der Klinikbetreiber fordert schnellere Anerkennungsverfahren, denn derzeit warten Bewerberinnen und Bewerber im Schnitt acht Monate auf ihren Bescheid. Einige Bundesländer testen deshalb digitale Antragsverfahren, mit denen sich die Wartezeit halbieren soll.“\n\nWorum werben deutsche Krankenhäuser laut Text?', 'multiple_choice', '["Um Personal aus dem Ausland", "Um mehr Patienten", "Um private Investoren"]'::jsonb, 'Um Personal aus dem Ausland', '„Deutsche Krankenhäuser werben zunehmend im Ausland um Personal.“', 7, 2, 'mcq', 1
