INSERT INTO questions (test_module_id, question_text, question_type, options, correct_answer, explanation, "order", exam_part, task_type, points)
SELECT tm.id, E'Thema: Weiterbildung neben dem Beruf, vier Erfahrungen\n\nPerson a (Chidi): „Ich habe berufsbegleitend einen Meisterkurs gemacht, abends und am Wochenende. Es war anstrengend, aber mein Gehalt ist danach deutlich gestiegen. Rückblickend war der Verzicht auf Freizeit die beste Investition meines Lebens.“\n\nPerson b (Marta): „Mit zwei kleinen Kindern kam ein Abendkurs für mich nicht infrage. Ich habe stattdessen intern jede Chance genutzt, neue Aufgaben zu übernehmen, so habe ich ohne formalen Abschluss Verantwortung bekommen.“\n\nPerson c (Ravi): „Mein Arbeitgeber hat die Fortbildung komplett bezahlt und mir Arbeitszeit dafür freigegeben. Ohne diese Unterstützung hätte ich es nicht geschafft, ich finde, Betriebe müssten das viel häufiger anbieten.“\n\nPerson d (Nasrin): „Ich habe online studiert, in meinem eigenen Tempo, meist nachts. Das war finanziell die einzige Option. Der Abschluss hat mir dann den Wechsel in die IT-Branche ermöglicht, heute verdiene ich das Doppelte.“\n\nAussage 1: Wer konnte die Weiterbildung nur dank des Arbeitgebers machen?\n\nWelche Person passt?', 'multiple_choice', '["a", "b", "c", "d"]'::jsonb, 'c', 'Ravi: „Ohne diese Unterstützung hätte ich es nicht geschafft.“', 1, 1, 'matching', 1
FROM test_modules tm JOIN levels l ON tm.level_id = l.id JOIN skills s ON tm.skill_id = s.id
WHERE l.code = 'B2' AND s.code = 'reading';

