INSERT INTO questions (test_module_id, question_text, question_type, options, correct_answer, explanation, "order", exam_part, task_type, points)
SELECT tm.id, E'Sachtext, Anerkennung ausländischer Berufsabschlüsse:\n\n„Wer mit einem ausländischen Berufsabschluss in Deutschland arbeiten will, muss diesen in vielen Fällen anerkennen lassen, bei reglementierten Berufen wie der Pflege ist das sogar zwingend. Die Verfahren dauern offiziell drei Monate, in der Praxis vergehen jedoch oft mehr als acht, weil Unterlagen nachgefordert werden und Übersetzungen fehlen. Eine Studie des Instituts für Arbeitsmarktforschung beziffert die Kosten für Antragstellende auf durchschnittlich 600 Euro. Immerhin: Wer das Verfahren abschließt, verdient nach fünf Jahren im Schnitt so viel wie einheimische Fachkräfte. Expertinnen fordern deshalb, Antragstellende früh zu beraten und die Verfahren zu digitalisieren, statt sie durch immer neue Nachweispflichten zu verlängern.“\n\nBei welchen Berufen ist die Anerkennung zwingend erforderlich?', 'multiple_choice', '["Bei reglementierten Berufen wie der Pflege", "Bei allen Berufen", "Nur bei akademischen Berufen"]'::jsonb, 'Bei reglementierten Berufen wie der Pflege', '„… bei reglementierten Berufen wie der Pflege ist das sogar zwingend.“', 10, 2, 'mcq', 1
FROM test_modules tm JOIN levels l ON tm.level_id = l.id JOIN skills s ON tm.skill_id = s.id
WHERE l.code = 'B2' AND s.code = 'reading';

