INSERT INTO questions (test_module_id, question_text, question_type, options, correct_answer, explanation, "order", exam_part, task_type, points)
SELECT tm.id, E'Reportage, Simulation statt Stationsalltag?\n\n„Im Skills-Lab der Pflegeschule Bochum piepsen Monitore, doch der Patient ist eine Puppe: Auszubildende trainieren hier Notfälle, die im echten Stationsalltag zum Glück selten sind. Studienleiterin Dr. Weber sieht darin einen doppelten Vorteil: Fehler haben keine Folgen, und jede Übung lässt sich beliebig wiederholen. Kritik kommt von Praxisanleitern: Die Puppe stelle keine Fragen und habe keine Angst, wer nur simuliere, lerne den Umgang mit echten Menschen nicht. Die Schule reagiert darauf mit einem Mischmodell: Auf jede Simulationswoche folgen drei Wochen Praxiseinsatz. Erste Auswertungen zeigen, dass die Absolventen des Mischmodells in Prüfungen sicherer handeln, sich aber genauso oft überfordert fühlen wie früher, wenn Angehörige emotional reagieren.“\n\nWas ist der Hauptvorteil der Simulation laut Dr. Weber?', 'multiple_choice', '["Fehler bleiben folgenlos und Übungen sind wiederholbar", "Die Ausbildung wird billiger", "Die Auszubildenden brauchen keine Praxis mehr"]'::jsonb, 'Fehler bleiben folgenlos und Übungen sind wiederholbar', '„Fehler haben keine Folgen, und jede Übung lässt sich beliebig wiederholen.“', 16, 3, 'mcq', 1
FROM test_modules tm JOIN levels l ON tm.level_id = l.id JOIN skills s ON tm.skill_id = s.id
WHERE l.code = 'B2' AND s.code = 'reading';

